import sys

class Solution:
    def singleNumber(self, nums: list[int]) -> list[int]:
        xor = 0
        for num in nums:
            xor ^= num

        rightmost_set_bit = xor & -xor

        single1, single2 = 0, 0
        for num in nums:
            if num & rightmost_set_bit:
                single1 ^= num
            else:
                single2 ^= num

        return sorted([single1, single2])

