#include <numeric>

#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<int> singleNumber(vector<int>& nums) {
        int xor_result = 0;
        for (int num : nums) {
            xor_result ^= num;
        }

        int rightmost_set_bit = xor_result & -xor_result;

        int single1 = 0, single2 = 0;
        for (int num : nums) {
            if (num & rightmost_set_bit) {
                single1 ^= num;
            } else {
                single2 ^= num;
            }
        }

        return {min(single1, single2), max(single1, single2)};
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    Solution sol;
    vector<int> ans = sol.singleNumber(nums);
    for (int i = 0; i < ans.size(); i++) {
        cout << ans[i] << (i == ans.size() - 1 ? "" : " ");
    }
    cout << "\n";
    return 0;
}
